   173|/**
   174| * Read the source of a generated feature file so the live coding stream can show
   175| * the real characters written. Stays inside the repo, caps size, and never throws.
   176| */
   177|async function readGeneratedFeatureSource(sourceFile: string | null): Promise<string | null> {
   178|  if (!sourceFile || typeof sourceFile !== 'string') {
   179|    return null;
   180|  }
   181|  try {
   182|    const root = process.cwd();
   183|    const resolved = path.resolve(root, sourceFile);
   184|    if (!resolved.startsWith(root)) {
   185|      return null;
   186|    }
   187|    const contents = await readFile(resolved, 'utf8');
   188|    return contents.length > 12000 ? `${contents.slice(0, 12000)}\n… (truncated)` : contents;
   189|  } catch {
   190|    return null;
   191|  }
