   198|/**
   199| * Drive a task to completion in the background, one block at a time. Safe to call
   200| * fire-and-forget. Re-reads task + blocks each loop so a pause/cancel issued via
   201| * the API takes effect between blocks, and so a crash mid-block resumes cleanly.
   202| */
   203|export async function driveTask(taskId: string, executor: IVXBlockExecutor = defaultBlockExecutor): Promise<void> {
   204|  if (activeRuns.has(taskId)) {
   205|    return;
   206|  }
   207|  activeRuns.add(taskId);
   208|  try {
   209|    let task = await getTask(taskId);
   210|    if (!task) {
   211|      return;
   212|    }
   213|    await updateTask(taskId, { status: 'running', error: null });
   214|
   215|    while (true) {
   216|      task = await getTask(taskId);
   217|      if (!task) {
   218|        return;
   219|      }
   220|      if (task.status === 'paused' || task.status === 'cancelled') {
   221|        await appendTaskEvent(taskId, { type: 'TASK_HALTED', blockId: null, detail: task.status });
   222|        return;
   223|      }
   224|
   225|      const blocks = await getTaskBlocks(taskId);
   226|      const block = findResumeBlock(blocks);
   227|
   228|      if (!block) {
   229|        // No runnable block left — settle the task status from the block roll-ups.
   230|        await finalizeTaskStatus(taskId);
   231|        return;
   232|      }
   233|
   234|      if (block.attempts >= MAX_ATTEMPTS_PER_BLOCK) {
   235|        await updateTaskBlock(taskId, block.id, {
   236|          status: 'FAILED',
   237|          error: `Exceeded ${MAX_ATTEMPTS_PER_BLOCK} attempts.`,
   238|          blocker: block.blocker ?? `Block failed after ${MAX_ATTEMPTS_PER_BLOCK} attempts.`,
   239|        });
   240|        continue;
   241|      }
   242|
   243|      await updateTaskBlock(taskId, block.id, {
   244|        status: 'RUNNING',
   245|        startedAt: block.startedAt ?? new Date().toISOString(),
   246|        attempts: block.attempts + 1,
   247|      });
   248|      await appendTaskEvent(taskId, { type: 'BLOCK_STARTED', blockId: block.id, detail: block.title });
   249|
   250|      let result: IVXBlockExecutionResult;
   251|      try {
   252|        result = await executor(block, task);
   253|      } catch (error) {
   254|        // A thrown executor is treated as a recoverable crash — persist details
   255|        // and let the loop resume this same block (until attempts are exhausted).
   256|        const message = error instanceof Error ? error.message : 'Executor crashed.';
   257|        await recordCrash(taskId, block.id, message);
   258|        await updateTaskBlock(taskId, block.id, { status: 'PENDING', error: message });
   259|        const after = await getTask(taskId);
   260|        if (!after || after.recoveryCount >= MAX_RECOVERIES) {
   261|          await updateTaskBlock(taskId, block.id, { status: 'FAILED', blocker: `Crash recovery cap reached: ${message}` });
   262|          await finalizeTaskStatus(taskId);
   263|          return;
   264|        }
   265|        continue;
   266|      }
   267|
   268|      const completedAt = ['VERIFIED', 'BUILT_NOT_DEPLOYED', 'BLOCKED', 'FAILED'].includes(result.status) ? new Date().toISOString() : null;
   269|      await updateTaskBlock(taskId, block.id, {
   270|        status: result.status,
   271|        codeChanges: result.codeChanges ?? block.codeChanges,
   272|        codeDiff: result.codeDiff ?? block.codeDiff,
   273|        validationCommand: result.validationCommand ?? block.validationCommand,
   274|        testResult: result.testResult ?? block.testResult,
   275|        commitHash: result.commitHash ?? block.commitHash,
   276|        deploymentStatus: result.deploymentStatus ?? block.deploymentStatus,
   277|        verification: result.verification ?? block.verification,
   278|        filesInvolved: result.filesInvolved ?? block.filesInvolved,
   279|        blocker: result.blocker ?? null,
   280|        error: result.error ?? null,
   281|        completedAt,
   282|      });
   283|
   284|      if (result.deploymentStatus) {
   285|        await updateTask(taskId, { deploymentStatus: result.deploymentStatus });
   286|      }
   287|
   288|      // Emit the real written code as a forensics event so the live coding stream
   289|      // can render the exact characters IVX produced for this block.
   290|      if (result.codeDiff && result.codeDiff.trim()) {
   291|        await appendTaskEvent(taskId, {
   292|          type: 'CODE_STREAM',
   293|          blockId: block.id,
   294|          detail: result.codeDiff.slice(0, 8000),
   295|        });
   296|      }
   297|
   298|      // BLOCKED / FAILED blocks do not stop the run — the loop advances to the
   299|      // next runnable block so independent work still completes. The final review
   300|      // surfaces every blocked/failed block to the owner.
   301|    }
   302|  } finally {
   303|    activeRuns.delete(taskId);
   304|  }
