   306|
   307|/**
   308| * Settle the overall task status from the authoritative block roll-ups.
   309| * A task is only 'completed' (success) when ALL blocks are VERIFIED.
   310| * BUILT_NOT_DEPLOYED blocks mean the task is NOT complete — the code was
   311| * written but never shipped, so the task stays 'blocked' with the real reason.
   312| */
   313|async function finalizeTaskStatus(taskId: string): Promise<IVXTaskRecord | null> {
   314|  const blocks = await getTaskBlocks(taskId);
   315|  const anyFailed = blocks.some((block) => block.status === 'FAILED');
   316|  const anyBlocked = blocks.some((block) => block.status === 'BLOCKED');
   317|  const anyBuiltNotDeployed = blocks.some((block) => block.status === 'BUILT_NOT_DEPLOYED');
   318|  const allVerified = blocks.length > 0 && blocks.every((block) => block.status === 'VERIFIED');
   319|
   320|  let status: IVXTaskRecord['status'];
   321|  if (allVerified) {
   322|    status = 'completed';
   323|  } else if (anyFailed) {
   324|    status = 'failed';
   325|  } else if (anyBlocked || anyBuiltNotDeployed) {
   326|    // BUILT_NOT_DEPLOYED is a deploy blocker — the task did not ship.
   327|    status = 'blocked';
   328|  } else {
   329|    status = 'blocked';
   330|  }
   331|
   332|  const deployBlocker = anyBuiltNotDeployed
   333|    ? `${blocks.filter((b) => b.status === 'BUILT_NOT_DEPLOYED').length} block(s) built but never deployed (BUILT_NOT_DEPLOYED).`
   334|    : null;
   335|  const settled = await updateTask(taskId, { status, completedAt: allVerified ? new Date().toISOString() : null, error: deployBlocker });
   336|  await appendTaskEvent(taskId, { type: `TASK_${status.toUpperCase()}`, blockId: null, detail: `${blocks.length} blocks${deployBlocker ? ` — ${deployBlocker}` : ''}` });
   337|  return settled;
   338|}
