   340|/** Persist crash details and bump the recovery counter. */
   341|export async function recordCrash(taskId: string, blockId: string | null, detail: string): Promise<void> {
   342|  const task = await getTask(taskId);
   343|  await updateTask(taskId, {
   344|    lastCrash: { at: new Date().toISOString(), detail, blockId },
   345|    recoveryCount: (task?.recoveryCount ?? 0) + 1,
   346|  });
   347|  await appendTaskEvent(taskId, { type: 'CRASH_RECORDED', blockId, detail });
   348|}
