   350|/** Create a crash-safe task: copy the original exactly, split into blocks, start. */
   351|export async function startTask(
   352|  ownerCommand: string,
   353|  options: { autoStart?: boolean; executor?: IVXBlockExecutor } = {},
   354|): Promise<{ task: IVXTaskRecord; blocks: IVXTaskBlock[] }> {
   355|  const original = ownerCommand;
   356|  const planned = splitTaskIntoBlocks(original);
   357|  const { task, blocks } = await createTask({
   358|    ownerCommand: original,
   359|    originalTask: original,
   360|    blocks: planned.length > 0 ? planned : [{ title: 'Task', goal: original }],
   361|  });
   362|  console.log('[IVXTaskOrchestrator] TASK_CREATED', { taskId: task.id, totalBlocks: task.totalBlocks });
   363|  if (options.autoStart !== false) {
   364|    void driveTask(task.id, options.executor ?? defaultBlockExecutor);
   365|  }
   366|  return { task, blocks };
   367|}
