   369|/**
   370| * Resume a task after a crash, pause, or process restart. Continues from the last
   371| * unfinished block — completed blocks are kept, the original task is preserved.
   372| */
   373|export async function resumeTask(
   374|  taskId: string,
   375|  executor: IVXBlockExecutor = defaultBlockExecutor,
   376|): Promise<IVXTaskRecord | null> {
   377|  const task = await getTask(taskId);
   378|  if (!task) {
   379|    return null;
   380|  }
   381|  if (isTerminalTaskStatus(task.status)) {
   382|    return task;
   383|  }
   384|  if (activeRuns.has(taskId)) {
   385|    return task;
   386|  }
   387|  const blocks = await getTaskBlocks(taskId);
   388|  const resumeBlock = findResumeBlock(blocks);
   389|  // A RUNNING block left over from a crash should be retried, not abandoned.
   390|  if (resumeBlock && resumeBlock.status === 'RUNNING') {
   391|    await updateTaskBlock(taskId, resumeBlock.id, { status: 'PENDING' });
   392|  }
   393|  await appendTaskEvent(taskId, {
   394|    type: 'TASK_RESUMED',
   395|    blockId: resumeBlock?.id ?? null,
   396|    detail: resumeBlock ? `from block ${resumeBlock.index + 1}` : 'no unfinished block',
   397|  });
   398|  const resumed = await updateTask(taskId, { status: 'running', error: null });
   399|  void driveTask(taskId, executor);
   400|  return resumed ?? task;
   401|}
   402|
   403|export async function pauseTask(taskId: string): Promise<IVXTaskRecord | null> {
   404|  const task = await getTask(taskId);
   405|  if (!task || isTerminalTaskStatus(task.status)) {
   406|    return task;
   407|  }
   408|  return await updateTask(taskId, { status: 'paused' });
   409|}
   410|
   411|export async function cancelTask(taskId: string): Promise<IVXTaskRecord | null> {
   412|  const task = await getTask(taskId);
   413|  if (!task) {
   414|    return null;
   415|  }
   416|  return await updateTask(taskId, { status: 'cancelled', completedAt: new Date().toISOString() });
   417|}
