   419|export type IVXTaskFinalReview = {
   420|  taskId: string;
   421|  originalTask: string;
   422|  status: IVXTaskRecord['status'];
   423|  totalBlocks: number;
   424|  completedBlocks: number;
   425|  builtNotDeployedBlocks: number;
   426|  failedBlocks: number;
   427|  blockedBlocks: number;
   428|  verifiedBlocks: number;
   429|  deployedBlocks: number;
   430|  filesChanged: string[];
