   438|/** Assemble the end-to-end final owner report from durable block state. */
   439|export async function buildTaskFinalReview(taskId: string): Promise<IVXTaskFinalReview | null> {
   440|  const task = await getTask(taskId);
   441|  if (!task) {
   442|    return null;
   443|  }
   444|  const blocks = await getTaskBlocks(taskId);
   445|  const filesChanged = [...new Set(blocks.flatMap((block) => block.filesInvolved))].filter(Boolean);
   446|  const commitHashes = [...new Set(blocks.map((block) => block.commitHash).filter((hash): hash is string => Boolean(hash)))];
   447|  const remainingIssues = blocks
   448|    .filter((block) => block.status === 'FAILED' || block.status === 'BLOCKED')
   449|    .map((block) => `Block ${block.index + 1} (${block.title}) — ${block.status}: ${block.blocker ?? block.error ?? 'see logs'}`);
   450|  const testsPassed = blocks.filter((block) => (block.testResult ?? '').toLowerCase().startsWith('passed')).length;
   451|
   452|  return {
   453|    taskId: task.id,
   454|    originalTask: task.originalTask,
   455|    status: task.status,
   456|    totalBlocks: blocks.length,
   457|    completedBlocks: blocks.filter((block) => block.status === 'VERIFIED' || block.status === 'BUILT_NOT_DEPLOYED').length,
   458|    builtNotDeployedBlocks: blocks.filter((block) => block.status === 'BUILT_NOT_DEPLOYED').length,
   459|    failedBlocks: blocks.filter((block) => block.status === 'FAILED').length,
   460|    blockedBlocks: blocks.filter((block) => block.status === 'BLOCKED').length,
   461|    verifiedBlocks: blocks.filter((block) => block.status === 'VERIFIED').length,
   462|    deployedBlocks: blocks.filter((block) => block.status === 'VERIFIED').length,
   463|    filesChanged,
   464|    commitHashes,
   465|    deploymentStatus: task.deploymentStatus,
   466|    testsPassed,
   467|    remainingIssues,
   468|    blocks,
   469|  };
   470|}
