   472|/**
   473| * On boot, find tasks that were mid-flight (running) when the process died and
   474| * resume them from their durable cursor. Returns the ids it resumed.
   475| */
   476|export async function recoverInterruptedTasks(
   477|  listFn: () => Promise<IVXTaskRecord[]>,
   478|  executor: IVXBlockExecutor = defaultBlockExecutor,
   479|): Promise<string[]> {
   480|  const tasks = await listFn();
   481|  const resumed: string[] = [];
   482|  for (const task of tasks) {
   483|    if (task.status === 'running' && !activeRuns.has(task.id)) {
   484|      await recordCrash(task.id, task.currentBlockId, 'Process restart detected — resuming from durable cursor.');
   485|      await resumeTask(task.id, executor);
   486|      resumed.push(task.id);
   487|    }
   488|  }
   489|  return resumed;
