   695|function buildProviderReadiness(rows: OwnerVariableRow[]): Record<OwnerVariableProvider, ProviderReadiness> {
   696|  const rowByName = new Map(rows.map((row) => [row.name, row]));
   697|  const providers = Array.from(new Set(OWNER_VARIABLES.map((item) => item.provider))) as OwnerVariableProvider[];
   698|  return Object.fromEntries(providers.map((provider) => {
   699|    const required = OWNER_VARIABLES.filter((item) => item.provider === provider && item.required).map((item) => item.name);
   700|    // A required variable is satisfied if it's in the encrypted store OR in the backend runtime env.
   701|    const saved = required.filter((name) => rowByName.has(name) || readEnv(name));
   702|    const missing = required.filter((name) => !rowByName.has(name) && !readEnv(name));
   703|    const providerRows = OWNER_VARIABLES.filter((item) => item.provider === provider).map((item) => rowByName.get(item.name)).filter((row): row is OwnerVariableRow => Boolean(row));
   704|    const hasInvalid = providerRows.some((row) => row.status === 'invalid');
   705|    const hasTested = required.length > 0 && required.every((name) => rowByName.get(name)?.status === 'tested');
   706|    const lastTestedAt = providerRows
   707|      .map((row) => row.last_tested_at)
   708|      .filter((value): value is string => Boolean(value))
   709|      .sort()
   710|      .at(-1) ?? null;
   711|    const status: ProviderReadiness['status'] = missing.length > 0 ? 'missing' : hasInvalid ? 'invalid' : hasTested ? 'tested' : 'saved';
   712|    return [provider, {
   713|      provider,
   714|      status,
   715|      requiredVariableNames: required,
   716|      savedVariableNames: saved,
   717|      missingVariableNames: missing,
   718|      lastTestedAt,
   719|      secretValuesReturned: false as const,
   720|    }];
   721|  })) as Record<OwnerVariableProvider, ProviderReadiness>;
