   780|  } catch (error) {
   781|    console.log('[IVXOwnerVariables] Runtime value bridge unavailable:', {
   782|      name,
   783|      message: error instanceof Error ? sanitizeExternalErrorDetail(error.message) : 'unknown',
   784|    });
